#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define BLOCK_SIZE 16
#define BLOCK_SIZE_C BLOCK_SIZE
#define BLOCK_SIZE_R BLOCK_SIZE

#define STR_SIZE 256

#define MAX_PD (3.0e6f)

#define PRECISION 0.001f
#define SPEC_HEAT_SI 1.75e6f
#define K_SI 100.0f

#define FACTOR_CHIP 0.5f

#define amb_temp 80.0f

#define chip_height 0.016f
#define chip_width 0.016f
#define t_chip 0.0005f

__kernel void hotspot(
    const int num_iterations,
    __global const float* power,
    __global const float* temp_in,
    __global float* temp_out,
    const int col,
    const int row,
    const int borderCols,
    const int borderRows,
    const float Cap,
    const float Rx,
    const float Ry,
    const float Rz,
    const float step)
{
    int gid_x = get_global_id(0);
    int gid_y = get_global_id(1);

    int blockCols = get_global_size(0) / BLOCK_SIZE;
    int blockRows = get_global_size(1) / BLOCK_SIZE;

    int chunk = gid_y * blockCols + gid_x;

    int chunks_in_row = col / BLOCK_SIZE_C;
    int chunks_in_col = row / BLOCK_SIZE_R;

    int r_start = BLOCK_SIZE_R * (chunk / chunks_in_col);
    int c_start = BLOCK_SIZE_C * (chunk % chunks_in_row);

    int r_end = (row < r_start + BLOCK_SIZE_R) ? row : (r_start + BLOCK_SIZE_R);
    int c_end = (c_start + BLOCK_SIZE_C > col) ? col : (c_start + BLOCK_SIZE_C);

    // Each work-item processes one element in the block
    int local_r = get_local_id(1);
    int local_c = get_local_id(0);

    // Compute global row and col for this thread
    int r = r_start + local_r;
    int c = c_start + local_c;

    // Bounds check
    if (r >= row || c >= col) return;

    // We will do num_iterations iterations inside kernel
    // Use two pointers to ping-pong between temp_in and temp_out
    // But since OpenCL kernel is launched once per iteration batch,
    // we do one iteration per kernel launch. So here we do one iteration.

    // Compute delta for this cell
    float delta = 0.0f;
    float Cap_1 = step / Cap;
    float Rx_1 = 1.0f / Rx;
    float Ry_1 = 1.0f / Ry;
    float Rz_1 = 1.0f / Rz;

    // For boundary cells, handle separately
    if (r_start == 0 || c_start == 0 || r_end == row || c_end == col) {
        // Boundary cells
        if (r == 0 && c == 0) {
            delta = Cap_1 * (power[0] +
                (temp_in[1] - temp_in[0]) * Rx_1 +
                (temp_in[col] - temp_in[0]) * Ry_1 +
                (amb_temp - temp_in[0]) * Rz_1);
        }
        else if (r == 0 && c == col - 1) {
            int idx = c;
            delta = Cap_1 * (power[idx] +
                (temp_in[idx - 1] - temp_in[idx]) * Rx_1 +
                (temp_in[idx + col] - temp_in[idx]) * Ry_1 +
                (amb_temp - temp_in[idx]) * Rz_1);
        }
        else if (r == row - 1 && c == col - 1) {
            int idx = r * col + c;
            delta = Cap_1 * (power[idx] +
                (temp_in[idx - 1] - temp_in[idx]) * Rx_1 +
                (temp_in[(r - 1) * col + c] - temp_in[idx]) * Ry_1 +
                (amb_temp - temp_in[idx]) * Rz_1);
        }
        else if (r == row - 1 && c == 0) {
            int idx = r * col;
            delta = Cap_1 * (power[idx] +
                (temp_in[idx + 1] - temp_in[idx]) * Rx_1 +
                (temp_in[(r - 1) * col] - temp_in[idx]) * Ry_1 +
                (amb_temp - temp_in[idx]) * Rz_1);
        }
        else if (r == 0) {
            int idx = c;
            delta = Cap_1 * (power[idx] +
                (temp_in[idx + 1] + temp_in[idx - 1] - 2.0f * temp_in[idx]) * Rx_1 +
                (temp_in[col + idx] - temp_in[idx]) * Ry_1 +
                (amb_temp - temp_in[idx]) * Rz_1);
        }
        else if (c == col - 1) {
            int idx = r * col + c;
            delta = Cap_1 * (power[idx] +
                (temp_in[(r + 1) * col + c] + temp_in[(r - 1) * col + c] - 2.0f * temp_in[idx]) * Ry_1 +
                (temp_in[idx - 1] - temp_in[idx]) * Rx_1 +
                (amb_temp - temp_in[idx]) * Rz_1);
        }
        else if (r == row - 1) {
            int idx = r * col + c;
            delta = Cap_1 * (power[idx] +
                (temp_in[idx + 1] + temp_in[idx - 1] - 2.0f * temp_in[idx]) * Rx_1 +
                (temp_in[(r - 1) * col + c] - temp_in[idx]) * Ry_1 +
                (amb_temp - temp_in[idx]) * Rz_1);
        }
        else if (c == 0) {
            int idx = r * col;
            delta = Cap_1 * (power[idx] +
                (temp_in[(r + 1) * col] + temp_in[(r - 1) * col] - 2.0f * temp_in[idx]) * Ry_1 +
                (temp_in[idx + 1] - temp_in[idx]) * Rx_1 +
                (amb_temp - temp_in[idx]) * Rz_1);
        }
        temp_out[r * col + c] = temp_in[r * col + c] + delta;
    }
    else {
        // Interior cells
        int idx = r * col + c;
        delta = Cap_1 * (power[idx] +
            (temp_in[(r + 1) * col + c] + temp_in[(r - 1) * col + c] - 2.0f * temp_in[idx]) * Ry_1 +
            (temp_in[r * col + c + 1] + temp_in[r * col + c - 1] - 2.0f * temp_in[idx]) * Rx_1 +
            (amb_temp - temp_in[idx]) * Rz_1);
        temp_out[idx] = temp_in[idx] + delta;
    }
}
